    // ── PAGE 5: Date ─────────────────────────────────────────────────────────
    public static class DatePage extends Fragment implements StudioFragment.OnStudioResetListener {
        @Override
        public void onResume() {
            super.onResume();
            StudioFragment.registerResetListener(this);
        }

        @Override
        public void onPause() {
            super.onPause();
            StudioFragment.unregisterResetListener(this);
        }

        @Override
        public void onStudioReset() {
            if (!isAdded() || getView() == null) return;
            StudioFragment st = getStudio(this);
            if (st == null) return;
            JSONObject d = st.getEffectiveDate();

            SwitchCompat swDate = getView().findViewById(R.id.sw_date_visible);
            View dateCtrl = getView().findViewById(R.id.layout_date_controls);
            boolean vis = d.optBoolean("visible", true);
            if (swDate != null) swDate.setChecked(vis);
            if (dateCtrl != null) dateCtrl.setVisibility(vis ? View.VISIBLE : View.GONE);

            SwitchCompat swAbove = getView().findViewById(R.id.sw_date_above_mask);
            if (swAbove != null) swAbove.setChecked(d.optBoolean("aboveMask", false));

            SeekBar seekDs = getView().findViewById(R.id.seek_date_size);
            TextView tvDs = getView().findViewById(R.id.tv_date_size_val);
            int size = (int) d.optDouble("size", 40);
            if (seekDs != null) {
                seekDs.setProgress(Math.min(200, Math.max(0, size)));
                if (tvDs != null) tvDs.setText(size + "sp");
            }

            SeekBar seekDx = getView().findViewById(R.id.seek_date_x);
            TextView tvDx = getView().findViewById(R.id.tv_date_x_val);
            int x = (int) (d.optDouble("x", 0.5) * 100);
            if (seekDx != null) {
                seekDx.setProgress(Math.min(100, Math.max(0, x)));
                if (tvDx != null) tvDx.setText(x + "%");
            }

            SeekBar seekDy = getView().findViewById(R.id.seek_date_y);
            TextView tvDy = getView().findViewById(R.id.tv_date_y_val);
            int y = (int) (d.optDouble("y", 0.75) * 100);
            if (seekDy != null) {
                seekDy.setProgress(Math.min(100, Math.max(0, y)));
                if (tvDy != null) tvDy.setText(y + "%");
            }

            SeekBar seekDr = getView().findViewById(R.id.seek_date_rot);
            TextView tvDr = getView().findViewById(R.id.tv_date_rot_val);
            float rot = (float) d.optDouble("rotation", 0);
            if (seekDr != null) {
                seekDr.setProgress((int) (rot + 180));
                if (tvDr != null) tvDr.setText((int) rot + "°");
            }
        }

        @Nullable
        @Override
        public View onCreateView(@NonNull LayoutInflater inf, @Nullable ViewGroup c, @Nullable Bundle s) {
            View v = inf.inflate(R.layout.studio_page_date, c, false);
            StudioFragment st = getStudio(this);
            if (st == null) return v;
            JSONObject effectiveDate = st.getEffectiveDate();

            // Toggle
            SwitchCompat swDate = v.findViewById(R.id.sw_date_visible);
            View dateCtrl = v.findViewById(R.id.layout_date_controls);
            boolean initVis = effectiveDate.optBoolean("visible", true);
            swDate.setChecked(initVis);
            dateCtrl.setVisibility(initVis ? View.VISIBLE : View.GONE);
            swDate.setOnCheckedChangeListener((b2, ch) -> {
                dateCtrl.setVisibility(ch ? View.VISIBLE : View.GONE);
                StudioManager.setDateVisible(requireContext(), ch);
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_reset_date_visible).setOnClickListener(b -> {
                swDate.setChecked(true);
                StudioManager.resetDateKey(requireContext(), "visible");
                st.scheduleRefresh();
                st.broadcastChange();
            });

            // ── Date Layer: above/below mask ──
            SwitchCompat swAbove = v.findViewById(R.id.sw_date_above_mask);
            if (swAbove != null) {
                swAbove.setChecked(effectiveDate.optBoolean("aboveMask", false));
                swAbove.setOnCheckedChangeListener((b2, ch) -> {
                    StudioManager.setDateAboveMask(requireContext(), ch);
                    st.scheduleRefresh();
                    st.broadcastChange();
                });
            }
            View resetAbove = v.findViewById(R.id.btn_reset_date_above_mask);
            if (resetAbove != null) {
                resetAbove.setOnClickListener(b -> {
                    swAbove.setChecked(false);
                    StudioManager.resetDateKey(requireContext(), "aboveMask");
                    st.scheduleRefresh();
                    st.broadcastChange();
                });
            }

            // ── Date Font Size ──
            SeekBar seekDs = v.findViewById(R.id.seek_date_size);
            TextView tvDs = v.findViewById(R.id.tv_date_size_val);
            int initDs = (int) effectiveDate.optDouble("size", 40);
            seekDs.setProgress(Math.min(200, Math.max(0, initDs)));
            tvDs.setText(initDs + "sp");
            seekDs.setOnSeekBarChangeListener(simple(val -> {
                tvDs.setText(val + "sp");
                StudioManager.setDateFontSize(requireContext(), val);
                st.scheduleRefresh();
                st.broadcastChange();
            }));
            v.findViewById(R.id.btn_reset_date_size).setOnClickListener(b -> {
                StudioManager.resetDateKey(requireContext(), "size");
                seekDs.setProgress(40);
                tvDs.setText("40sp");
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_minus_date_size).setOnClickListener(b -> {
                int next = Math.max(0, Math.min(seekDs.getMax(), seekDs.getProgress() - 1));
                seekDs.setProgress(next);
                tvDs.setText(next + "sp");
                StudioManager.setDateFontSize(requireContext(), next);
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_plus_date_size).setOnClickListener(b -> {
                int next = Math.max(0, Math.min(seekDs.getMax(), seekDs.getProgress() + 1));
                seekDs.setProgress(next);
                tvDs.setText(next + "sp");
                StudioManager.setDateFontSize(requireContext(), next);
                st.scheduleRefresh();
                st.broadcastChange();
            });

            // ── Date X ──
            SeekBar seekDx = v.findViewById(R.id.seek_date_x);
            TextView tvDx = v.findViewById(R.id.tv_date_x_val);
            int initDx = (int) (effectiveDate.optDouble("x", 0.5) * 100);
            seekDx.setProgress(initDx);
            tvDx.setText(initDx + "%");
            seekDx.setOnSeekBarChangeListener(simple(val -> {
                tvDx.setText(val + "%");
                StudioManager.setDatePosX(requireContext(), val / 100f);
                st.scheduleRefresh();
                st.broadcastChange();
            }));
            v.findViewById(R.id.btn_reset_date_x).setOnClickListener(b -> {
                StudioManager.resetDateKey(requireContext(), "x");
                seekDx.setProgress(50);
                tvDx.setText("50%");
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_minus_date_x).setOnClickListener(b -> {
                int next = Math.max(0, Math.min(seekDx.getMax(), seekDx.getProgress() - 1));
                seekDx.setProgress(next);
                tvDx.setText(next + "%");
                StudioManager.setDatePosX(requireContext(), next / 100f);
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_plus_date_x).setOnClickListener(b -> {
                int next = Math.max(0, Math.min(seekDx.getMax(), seekDx.getProgress() + 1));
                seekDx.setProgress(next);
                tvDx.setText(next + "%");
                StudioManager.setDatePosX(requireContext(), next / 100f);
                st.scheduleRefresh();
                st.broadcastChange();
            });

            // ── Date Y ──
            SeekBar seekDy = v.findViewById(R.id.seek_date_y);
            TextView tvDy = v.findViewById(R.id.tv_date_y_val);
            int initDy = (int) (effectiveDate.optDouble("y", 0.75) * 100);
            seekDy.setProgress(initDy);
            tvDy.setText(initDy + "%");
            seekDy.setOnSeekBarChangeListener(simple(val -> {
                tvDy.setText(val + "%");
                StudioManager.setDatePosY(requireContext(), val / 100f);
                st.scheduleRefresh();
                st.broadcastChange();
            }));
            v.findViewById(R.id.btn_reset_date_y).setOnClickListener(b -> {
                StudioManager.resetDateKey(requireContext(), "y");
                seekDy.setProgress(75);
                tvDy.setText("75%");
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_minus_date_y).setOnClickListener(b -> {
                int next = Math.max(0, Math.min(seekDy.getMax(), seekDy.getProgress() - 1));
                seekDy.setProgress(next);
                tvDy.setText(next + "%");
                StudioManager.setDatePosY(requireContext(), next / 100f);
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_plus_date_y).setOnClickListener(b -> {
                int next = Math.max(0, Math.min(seekDy.getMax(), seekDy.getProgress() + 1));
                seekDy.setProgress(next);
                tvDy.setText(next + "%");
                StudioManager.setDatePosY(requireContext(), next / 100f);
                st.scheduleRefresh();
                st.broadcastChange();
            });

            // ── Date Rotation ──
            SeekBar seekDr = v.findViewById(R.id.seek_date_rot);
            TextView tvDr = v.findViewById(R.id.tv_date_rot_val);
            float initDr = (float) effectiveDate.optDouble("rotation", 0);
            seekDr.setProgress((int) (initDr + 180));
            tvDr.setText((int) initDr + "°");
            seekDr.setOnSeekBarChangeListener(simple(val -> {
                float d2 = val - 180f;
                tvDr.setText((int) d2 + "°");
                StudioManager.setDateRotation(requireContext(), d2);
                st.scheduleRefresh();
                st.broadcastChange();
            }));
            v.findViewById(R.id.btn_reset_date_rot).setOnClickListener(b -> {
                StudioManager.resetDateKey(requireContext(), "rotation");
                seekDr.setProgress(180);
                tvDr.setText("0°");
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_minus_date_rot).setOnClickListener(b -> {
                int next = Math.max(0, Math.min(seekDr.getMax(), seekDr.getProgress() - 1));
                seekDr.setProgress(next);
                float d2 = next - 180f;
                tvDr.setText((int) d2 + "°");
                StudioManager.setDateRotation(requireContext(), d2);
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_plus_date_rot).setOnClickListener(b -> {
                int next = Math.max(0, Math.min(seekDr.getMax(), seekDr.getProgress() + 1));
                seekDr.setProgress(next);
                float d2 = next - 180f;
                tvDr.setText((int) d2 + "°");
                StudioManager.setDateRotation(requireContext(), d2);
                st.scheduleRefresh();
                st.broadcastChange();
            });

            return v;
        }
    }

    // ── PAGE 6: Date Settings ────────────────────────────────────────────────
    public static class DateSettingsPage extends Fragment implements StudioFragment.OnStudioResetListener {
        @Override
        public void onResume() {
            super.onResume();
            StudioFragment.registerResetListener(this);
        }

        @Override
        public void onPause() {
            super.onPause();
            StudioFragment.unregisterResetListener(this);
        }

        @Override
        public void onStudioReset() {
            if (!isAdded() || getView() == null) return;
            StudioFragment st = getStudio(this);
            if (st == null) return;
            JSONObject d = st.getEffectiveDate();

            RadioGroup rgFmt = getView().findViewById(R.id.rg_date_format);
            if (rgFmt != null) setFmtRadio(rgFmt, d.optString("format", "EEE, dd MMM"));

            RecyclerView rvDF = getView().findViewById(R.id.rv_date_fonts);
            if (rvDF != null && rvDF.getAdapter() instanceof FontPickerAdapter)
                ((FontPickerAdapter) rvDF.getAdapter()).setSelected(d.optString("font", "main3.ttf"));

            InlineColorPicker cpDate = getView().findViewById(R.id.color_picker_date);
            View swDC = getView().findViewById(R.id.swatch_date_color);
            String col = d.optString("color", "#FFFFFF");
            if (cpDate != null) cpDate.setSelectedColor(col);
            if (swDC != null) trySetBg(swDC, col);

            SwitchCompat swCaps = getView().findViewById(R.id.sw_date_allcaps);
            if (swCaps != null) swCaps.setChecked(d.optBoolean("allCaps", false));
        }

        private void setFmtRadio(RadioGroup rg, String fmt) {
            if ("dd MMM yyyy".equals(fmt)) rg.check(R.id.rb_fmt_dd_mmm_yyyy);
            else if ("MMM dd".equals(fmt)) rg.check(R.id.rb_fmt_mmm_dd);
            else if ("dd/MM/yyyy".equals(fmt)) rg.check(R.id.rb_fmt_dd_mm_yyyy);
            else if ("MM/dd/yyyy".equals(fmt)) rg.check(R.id.rb_fmt_mm_dd_yyyy);
            else if ("EEEE".equals(fmt)) rg.check(R.id.rb_fmt_eeee);
            else if ("dd MMM".equals(fmt)) rg.check(R.id.rb_fmt_dd_mmm);
            else rg.check(R.id.rb_fmt_eee_dd_mmm);
        }

        @Nullable
        @Override
        public View onCreateView(@NonNull LayoutInflater inf, @Nullable ViewGroup c, @Nullable Bundle s) {
            View v = inf.inflate(R.layout.studio_page_date_settings, c, false);
            StudioFragment st = getStudio(this);
            if (st == null) return v;
            JSONObject effectiveDate = st.getEffectiveDate();

            RadioGroup rgFmt = v.findViewById(R.id.rg_date_format);
            setFmtRadio(rgFmt, effectiveDate.optString("format", "EEE, dd MMM"));
            rgFmt.setOnCheckedChangeListener((g, id) -> {
                String fmt = id == R.id.rb_fmt_dd_mmm_yyyy ? "dd MMM yyyy" : id == R.id.rb_fmt_mmm_dd ? "MMM dd" : id == R.id.rb_fmt_dd_mm_yyyy ? "dd/MM/yyyy" : id == R.id.rb_fmt_mm_dd_yyyy ? "MM/dd/yyyy" : id == R.id.rb_fmt_eeee ? "EEEE" : id == R.id.rb_fmt_dd_mmm ? "dd MMM" : "EEE, dd MMM";
                StudioManager.setDateFormat(requireContext(), fmt);
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_reset_date_fmt).setOnClickListener(b -> {
                StudioManager.resetDateKey(requireContext(), "format");
                rgFmt.check(R.id.rb_fmt_eee_dd_mmm);
                st.scheduleRefresh();
                st.broadcastChange();
            });

            RecyclerView rvDF = v.findViewById(R.id.rv_date_fonts);
            rvDF.setLayoutManager(new LinearLayoutManager(requireContext(), LinearLayoutManager.HORIZONTAL, false));
            FontPickerAdapter dfa = new FontPickerAdapter(requireContext(), StudioFragment.loadedFontsList, effectiveDate.optString("font", "main3.ttf"));
            dfa.setListener(fontItem -> {
                StudioManager.setDateFont(requireContext(), fontItem.id);
                st.scheduleRefresh();
                st.broadcastChange();
            });
            rvDF.setAdapter(dfa);
            v.findViewById(R.id.btn_reset_date_font).setOnClickListener(b -> {
                StudioManager.resetDateKey(requireContext(), "font");
                dfa.setSelected("main3.ttf");
                st.scheduleRefresh();
                st.broadcastChange();
            });

            String[] dc = {effectiveDate.optString("color", "#FFFFFF")};
            View swDC = v.findViewById(R.id.swatch_date_color);
            trySetBg(swDC, dc[0]);
            InlineColorPicker cpDate = v.findViewById(R.id.color_picker_date);
            if (cpDate != null) {
                cpDate.setSelectedColor(dc[0]);
                cpDate.setOnColorSelectedListener(hex -> {
                    dc[0] = hex;
                    trySetBg(swDC, hex);
                    StudioManager.setDateColor(requireContext(), hex);
                    st.scheduleRefresh();
                    st.broadcastChange();
                });
            } else {
                swDC.setOnClickListener(b -> ColorPickerDialog.show(requireContext(), dc[0], hex -> {
                    dc[0] = hex;
                    trySetBg(swDC, hex);
                    StudioManager.setDateColor(requireContext(), hex);
                    st.scheduleRefresh();
                    st.broadcastChange();
                }));
            }
            v.findViewById(R.id.btn_reset_date_color).setOnClickListener(b -> {
                StudioManager.resetDateKey(requireContext(), "color");
                dc[0] = st.getEffectiveDate().optString("color", "#FFFFFF");
                trySetBg(swDC, dc[0]);
                if (cpDate != null) cpDate.setSelectedColor(dc[0]);
                st.scheduleRefresh();
                st.broadcastChange();
            });

            SwitchCompat swCaps = v.findViewById(R.id.sw_date_allcaps);
            swCaps.setChecked(effectiveDate.optBoolean("allCaps", false));
            swCaps.setOnCheckedChangeListener((b2, ch) -> {
                StudioManager.setDateAllCaps(requireContext(), ch);
                st.scheduleRefresh();
                st.broadcastChange();
            });
            v.findViewById(R.id.btn_reset_date_allcaps).setOnClickListener(b -> {
                swCaps.setChecked(false);
                StudioManager.resetDateKey(requireContext(), "allCaps");
                st.scheduleRefresh();
                st.broadcastChange();
            });

            return v;
        }
    }

    private class StudioPagerAdapter extends FragmentStateAdapter {
        StudioPagerAdapter(Fragment f) {
            super(f);
        }

        @Override
        public int getItemCount() {
            return TAB_NAMES.length;
        }

        @NonNull
        @Override
        public Fragment createFragment(int pos) {
            switch (pos) {
                case 0:
                    return new BasicsPage();
                case 1:
                    return new TypographyPage();
                case 2:
                    return new EffectsPage();
                case 3:
                    return new TransformPage();
                case 4:
                    return new DatePage();
                case 5:
                    return new DateSettingsPage();
                default:
                    return new BasicsPage();
            }
        }
    }
}

package com.walle.wallpaper.ui.wallpapers;

import android.animation.ObjectAnimator;
import android.app.Dialog;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.view.animation.AccelerateDecelerateInterpolator;
import android.view.animation.OvershootInterpolator;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.google.firebase.firestore.FirebaseFirestore;
import com.google.firebase.firestore.QueryDocumentSnapshot;
import com.walle.wallpaper.R;
import com.walle.wallpaper.WallpaperApplier;
import com.walle.wallpaper.data.WallpaperItem;
import com.walle.wallpaper.ui.AdminFragment;
import com.walle.wallpaper.ui.common.PullAwareSwipeRefreshLayout;
import com.walle.wallpaper.ui.common.PullRevealRefreshController;
import com.walle.wallpaper.ui.common.ZigzagLoadingDialog;
import com.walle.wallpaper.util.SelectedWallpaperStore;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Map;

public class RecentFragment extends Fragment {

    private RecyclerView recycler;
    private RecentWallpaperAdapter adapter;
    private TextView emptyView;
    private PullAwareSwipeRefreshLayout swipeRefresh;
    private View refreshIndicatorContainer;
    private com.walle.wallpaper.ui.common.PulseRefreshView pulseRefresh;
    // guard against double-click spamming dialogs
    private Dialog activeDialog = null;
    private boolean isRefreshing = false;
    private PullRevealRefreshController refreshController;

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container, @Nullable Bundle savedInstanceState) {
        View root = inflater.inflate(R.layout.page_recent, container, false);
        recycler = root.findViewById(R.id.recycler_recent);
        emptyView = root.findViewById(R.id.empty_recent);
        swipeRefresh = root.findViewById(R.id.swipe_refresh);
        refreshIndicatorContainer = root.findViewById(R.id.refresh_indicator_container);
        pulseRefresh = root.findViewById(R.id.pulse_refresh);

        // Hide the default SwipeRefreshLayout indicator
        swipeRefresh.setProgressViewOffset(false, -200, -200);

        // Pull-to-reveal + release-to-animate behavior
        refreshController = new PullRevealRefreshController(swipeRefresh, refreshIndicatorContainer, pulseRefresh);
        refreshController.setOnRefresh(this::performRefresh);

        adapter = new RecentWallpaperAdapter(requireContext());
        adapter.setSelectedId(SelectedWallpaperStore.getSelectedId(requireContext()));

        recycler.setAdapter(adapter);
        recycler.setLayoutManager(new GridLayoutManager(requireContext(), 2));

        // ── Tap on a tile → choose theme or auto-apply when only one ──
        adapter.setItemClickListener(item -> {
            if (!isAdded()) return;
            SelectedWallpaperStore.setSelected(requireContext(), item);
            adapter.setSelectedId(item.id);

            int themeCount = getThemeCount(item);
            if (themeCount == 1) {
                // Directly apply the single available theme, no chooser bottom sheet
                String bg = item.bgUrl != null && !item.bgUrl.isEmpty() ? item.bgUrl : item.previewUrl;
                String mask = item.maskUrl;
                if (bg == null || bg.isEmpty()) return;

                Object themeObj = getSingleTheme(item);
                if (themeObj == null) {
                    themeObj = getFirstTheme(item);
                }

                if (activeDialog != null) return;
                activeDialog = ZigzagLoadingDialog.show(requireContext(), "Applying…  0%");

                Object finalThemeObj = themeObj;
                WallpaperApplier.prefetch(requireContext(), bg, mask, finalThemeObj,
                        pct -> ZigzagLoadingDialog.updateMessage(activeDialog, "Applying…  " + pct + "%"),
                        (success, error) -> {
                            if (!isAdded()) return;
                            requireActivity().runOnUiThread(() -> {
                                if (!success) {
                                    dismissActiveDialog();
                                    String msg = error != null ? error.getMessage() : "Unknown error";
                                    Toast.makeText(requireContext(), "Failed: " + msg, Toast.LENGTH_LONG).show();
                                    return;
                                }

                                // Show Ad immediately after prefetch succeeds
                                com.walle.wallpaper.ui.common.AdManager.showInterstitial(requireActivity(), () -> {
                                    // When ad finishes, check if we need to open the screen
                                    if (WallpaperApplier.isOurLiveWallpaperActive(requireContext())) {
                                        dismissActiveDialog();
                                        Toast.makeText(requireContext(), "Wallpaper applied successfully", Toast.LENGTH_SHORT).show();
                                    } else {
                                        dismissActiveDialog();
                                        WallpaperApplier.openSystemApplyScreen(requireContext());
                                    }
                                });
                                AdminFragment.incrementApplyCount(item.id);
                            });
                        });
                return;
            }

            // Multiple themes → show theme picker as before
            com.walle.wallpaper.ui.common.ThemePickerSheet.show(requireContext(), item, (themeKey, themeJson, selectedItem) -> {
                if (!isAdded()) return;
                String bg = selectedItem.bgUrl != null && !selectedItem.bgUrl.isEmpty() ? selectedItem.bgUrl : selectedItem.previewUrl;
                String mask = selectedItem.maskUrl;
                if (bg == null || bg.isEmpty()) return;
                Object themeObj = (themeJson != null && !themeJson.equals("{}")) ? themeJson : getFirstTheme(selectedItem);

                if (activeDialog != null) return;
                activeDialog = ZigzagLoadingDialog.show(requireContext(), "Applying… 0%");

                WallpaperApplier.prefetch(requireContext(), bg, mask, themeObj,
                        pct -> ZigzagLoadingDialog.updateMessage(activeDialog, "Applying…  " + pct + "%"),
                        (success, error) -> {
                            if (!isAdded()) return;
                            requireActivity().runOnUiThread(() -> {
                                if (!success) {
                                    dismissActiveDialog();
                                    String msg = error != null ? error.getMessage() : "Unknown error";
                                    Toast.makeText(requireContext(), "Failed: " + msg, Toast.LENGTH_LONG).show();
                                    return;
                                }

                                // Show Ad immediately after prefetch succeeds
                                com.walle.wallpaper.ui.common.AdManager.showInterstitial(requireActivity(), () -> {
                                    // When ad finishes, check if we need to open the screen
                                    if (WallpaperApplier.isOurLiveWallpaperActive(requireContext())) {
                                        dismissActiveDialog();
                                        Toast.makeText(requireContext(), "Wallpaper applied successfully ✓", Toast.LENGTH_SHORT).show();
                                    } else {
                                        dismissActiveDialog();
                                        WallpaperApplier.openSystemApplyScreen(requireContext());
                                    }
                                });
                                AdminFragment.incrementApplyCount(selectedItem.id);
                            });
                        });
            });

            // Keep selection listener for persisting selection
            adapter.setSelectionListener((position, selItem) -> {
                SelectedWallpaperStore.setSelected(requireContext(), selItem);
            });
        });

        loadWallpapers();
        return root;
    }

    private void dismissActiveDialog() {
        ZigzagLoadingDialog.dismiss(activeDialog);
        activeDialog = null;
    }

    private int getThemeCount(WallpaperItem item) {
        if (item == null || item.themes == null || item.themes.isEmpty()) return 0;
        int count = 0;
        for (Map.Entry<String, Object> e : item.themes.entrySet()) {
            Object v = e.getValue();
            if (v == null) continue;
            if (v instanceof String) {
                String s = (String) v;
                if (!s.trim().isEmpty() && !"{}".equals(s.trim())) count++;
            } else if (v instanceof Map) {
                if (!((Map<?, ?>) v).isEmpty()) count++;
            } else {
                count++;
            }
        }
        return count;
    }

    private Object getSingleTheme(WallpaperItem item) {
        if (item == null || item.themes == null || item.themes.isEmpty()) return null;
        Object last = null;
        int count = 0;
        for (Map.Entry<String, Object> e : item.themes.entrySet()) {
            Object v = e.getValue();
            if (v == null) continue;
            if (v instanceof String) {
                String s = (String) v;
                if (s.trim().isEmpty() || "{}".equals(s.trim())) continue;
            } else if (v instanceof Map) {
                if (((Map<?, ?>) v).isEmpty()) continue;
            }
            count++;
            last = v;
        }
        if (count == 1) {
            // Keep same representation type; ThemeRenderer/WallpaperApplier already handle String or Map
            return last;
        }
        return null;
    }

    private Object getFirstTheme(WallpaperItem item) {
        if (item.themes == null) return null;
        if (item.themes.containsKey("theme1")) return item.themes.get("theme1");
        for (Map.Entry<String, Object> e : item.themes.entrySet()) return e.getValue();
        return null;
    }

    private void performRefresh() {
        if (!isAdded() || isRefreshing) {
            if (swipeRefresh != null) swipeRefresh.setRefreshing(false);
            if (refreshController != null) refreshController.finish();
            return;
        }
        isRefreshing = true;

        FirebaseFirestore db = FirebaseFirestore.getInstance();
        db.collection("wallpapers").limit(50).get().addOnCompleteListener(task -> {
            if (!isAdded()) return;
            if (task.isSuccessful() && task.getResult() != null) {
                List<WallpaperItem> list = new ArrayList<>();
                for (QueryDocumentSnapshot doc : task.getResult()) {
                    WallpaperItem w = doc.toObject(WallpaperItem.class);
                    w.id = doc.getId();
                    com.google.firebase.Timestamp ts = doc.getTimestamp("createdAt");
                    if (ts != null) w.createdAt = ts.toDate().getTime();
                    list.add(w);
                }
                Collections.sort(list, (a, b) -> {
                    if (a.createdAt != 0 || b.createdAt != 0)
                        return Long.compare(b.createdAt, a.createdAt);
                    String na = a.name != null ? a.name : a.id;
                    String nb = b.name != null ? b.name : b.id;
                    return nb.compareToIgnoreCase(na);
                });

                final List<WallpaperItem> finalList = list;
                requireActivity().runOnUiThread(() -> {
                    if (refreshController != null) {
                        refreshController.runAfterMinVisible(() -> {
                            if (!isAdded()) return;
                            adapter.setItems(finalList);
                            adapter.setSelectedId(SelectedWallpaperStore.getSelectedId(requireContext()));
                            emptyView.setVisibility(finalList.isEmpty() ? View.VISIBLE : View.GONE);
                            animateRefreshComplete();
                        });
                    } else {
                        adapter.setItems(finalList);
                        adapter.setSelectedId(SelectedWallpaperStore.getSelectedId(requireContext()));
                        emptyView.setVisibility(finalList.isEmpty() ? View.VISIBLE : View.GONE);
                        animateRefreshComplete();
                    }
                });
            } else {
                requireActivity().runOnUiThread(() -> {
                    animateRefreshComplete();
                    Toast.makeText(requireContext(), "Failed to refresh", Toast.LENGTH_SHORT).show();
                });
            }
        });
    }

    private void animateRefreshComplete() {
        if (!isAdded()) return;

        if (refreshController != null) refreshController.finish();

        // Slide up + fade in animation
        recycler.setTranslationY(50f);
        recycler.setAlpha(0.3f);

        ObjectAnimator fadeIn = ObjectAnimator.ofFloat(recycler, "alpha", 0.3f, 1f);
        fadeIn.setDuration(350);
        fadeIn.setInterpolator(new AccelerateDecelerateInterpolator());

        ObjectAnimator slideUp = ObjectAnimator.ofFloat(recycler, "translationY", 50f, 0f);
        slideUp.setDuration(400);
        slideUp.setInterpolator(new OvershootInterpolator(0.8f));

        fadeIn.start();
        slideUp.start();

        swipeRefresh.setRefreshing(false);
        isRefreshing = false;
    }

    private void loadWallpapers() {
        adapter.setLoading(true);
        FirebaseFirestore db = FirebaseFirestore.getInstance();
        db.collection("wallpapers").limit(50).get().addOnCompleteListener(task -> {
            if (!isAdded()) return;
            if (task.isSuccessful() && task.getResult() != null) {
                List<WallpaperItem> list = new ArrayList<>();
                for (QueryDocumentSnapshot doc : task.getResult()) {
                    WallpaperItem w = doc.toObject(WallpaperItem.class);
                    w.id = doc.getId();
                    // capture createdAt from Firestore timestamp if present
                    com.google.firebase.Timestamp ts = doc.getTimestamp("createdAt");
                    if (ts != null) w.createdAt = ts.toDate().getTime();
                    list.add(w);
                }
                // Sort newest first: by createdAt desc, fallback alphabetical
                Collections.sort(list, (a, b) -> {
                    if (a.createdAt != 0 || b.createdAt != 0)
                        return Long.compare(b.createdAt, a.createdAt);
                    String na = a.name != null ? a.name : a.id;
                    String nb = b.name != null ? b.name : b.id;
                    return nb.compareToIgnoreCase(na);
                });
                requireActivity().runOnUiThread(() -> {
                    adapter.setItems(list);
                    adapter.setSelectedId(SelectedWallpaperStore.getSelectedId(requireContext()));
                    emptyView.setVisibility(list.isEmpty() ? View.VISIBLE : View.GONE);
                });
            } else {
                requireActivity().runOnUiThread(() -> {
                    adapter.setItems(new ArrayList<>());
                    emptyView.setVisibility(View.VISIBLE);
                });
            }
        });
    }
}

